import type { VenueProfile } from './venue-data';
import { VENUES } from './venue-data';

export interface EventTemplate {
  name: string;
  venueIndex: number;
  event: Record<string, unknown>;
  budget: Record<string, unknown>;
  companyInfo: Record<string, unknown>;
  meetingRoom: Record<string, unknown>;
  fnb: Record<string, unknown>;
  equipment: Record<string, unknown>;
  datetime: Record<string, unknown>;
  conferenceDay: Record<string, unknown>;
  roomBlock: Record<string, unknown>;
  stats: Record<string, unknown>;
}

function buildComponents(tpl: EventTemplate, venue: VenueProfile): Record<string, Record<string, unknown>> {
  return {
    event: tpl.event,
    budget: tpl.budget,
    'company-info': tpl.companyInfo,
    venue: { venue_id: venue.venue_id, venue_name: venue.venue_name },
    location: {
      name: venue.venue_name,
      address: venue.address,
      lat: venue.lat,
      lng: venue.lng,
      locality: venue.locality,
      zipcode: venue.zipcode,
      country: venue.country,
      country_code: venue.country_code,
    },
    'meeting-room': tpl.meetingRoom,
    'food-and-beverage': tpl.fnb,
    equipment: tpl.equipment,
    datetime: tpl.datetime,
    source: {
      channel: 'widget',
      external_rfp_id: `RFP-${Math.floor(10000 + Math.random() * 89999)}`,
      tracking_id: `trk-${Math.random().toString(36).slice(2, 7)}`,
      owner: 'pm@hotel.example',
      is_mailbot: false,
      is_outlook_addin: false,
      is_quote_generator: false,
      lead_source_name: 'Direct',
      supplier_id: `SUP-${venue.venue_id}`,
      hotel_unique_id: venue.hotel_unique_id,
      portal_name: 'Booking Widget',
    },
    'conference-day': tpl.conferenceDay,
    package: {
      name: 'Day Delegate Package',
      description: 'Standard package with refreshments and lunch',
      count: (tpl.event as { guests: number }).guests,
      calc_per: 'person',
      items: ['li_coffee', 'li_lunch', 'li_water'],
    },
    'line-item': {
      catalog_id: 'res-50',
      title: 'Business Lunch',
      title_multilang: [
        { lang: 'en', value: 'Business Lunch' },
        { lang: 'de', value: 'Business-Lunch' },
      ],
      count: (tpl.event as { guests: number }).guests,
      time_from: '12:00',
      time_to: '13:00',
      price_unit: 'per person',
      included_in_package: true,
      notes: '',
    },
    'room-block': tpl.roomBlock,
    deadline: {
      offer_deadline: `${(tpl.datetime as { from_date: string }).from_date.slice(0, 7)}-01T17:00:00+02:00`,
      option_due_date: `${(tpl.datetime as { from_date: string }).from_date.slice(0, 7)}-05T12:00:00+02:00`,
      timeout_date: null,
      policy_check_results: [{ rule: 'min_lead_time_days', passed: true }],
      history: [],
    },
    'policy-terms': {
      cancellation_terms: [
        { deadline: `${(tpl.datetime as { from_date: string }).from_date}T00:00:00+02:00`, penalty_type: 'percent', penalty_value: 50 },
      ],
      deposit_terms: [
        { due_date: `${(tpl.datetime as { from_date: string }).from_date.slice(0, 7)}-01`, percent: 30 },
      ],
    },
    stats: tpl.stats,
    content: {
      currency: 'EUR',
      process_overview: [
        { label: 'RFP received', at: new Date().toISOString() },
      ],
      attachments: [],
      remarks: [],
    },
    'availability-check': {
      date: (tpl.datetime as { from_date: string }).from_date,
      timezone: 'Europe/Berlin',
      is_calculated: true,
      event_date_available: true,
      alternate_date_available: false,
      capacity_confirmed: true,
      availability_confirmed: true,
      criteria: {
        pax: (tpl.event as { guests: number }).guests,
        seating: (tpl.meetingRoom as { seating: string }).seating || 'theater',
        time_from: '08:00',
        time_to: '18:00',
      },
      matching_rooms: [{ room_id: 'room_main', is_available: true }],
      available_rooms_without_combinations: [],
    },
    'integration-log': {
      system: 'pms',
      operation: 'Create',
      request_at: new Date().toISOString(),
      response_at: new Date().toISOString(),
      http_status: 200,
      result_status: 'SUCCESS',
      error_code: null,
      error_description: null,
      retryable: false,
      request_ref: '',
      response_ref: '',
    },
    misc: {},
  };
}

