export function getEventTemplates(indices: number[]): { name: string; components: Record<string, Record<string, unknown>> }[] {
  return indices.map((idx) => {
    const tpl = TEMPLATES[idx];
    const venue = VENUES[tpl.venueIndex];
    return {
      name: tpl.name,
      components: buildComponents(tpl, venue),
    };
  });
}

